arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now sets the UTF-8 flag for
        // non-ASCII names. The legacy Java consumer expects Shift-JIS, so we
        // force that encoding via the ZipArchive constructor to suppress the
        // UTF-8 flag and encode entry names in Shift-JIS.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift_JIS");
        using var fs = new FileStream("data.zip", FileMode.Create);
        using var archive = new ZipArchive(fs, ZipArchiveMode.Create, leaveOpen: false, entryNameEncoding: shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices] no longer falls back to
// non-keyed registrations. Register with the matching key.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

